{
 "level": "A1–A2",
 "intro": "In this topic you will learn <strong>the structure of a simple English sentence</strong>: what is a subject, predicate and object, and how to arrange them correctly according to the scheme S–V–O.",
 "rules": [
 {
 "label": "Subject (S)",
 "color": "emerald",
 "text": "<strong>Subject</strong> — who or what performs the action:",
 "example": "She / The cat / My friends"
 },
 {
 "label": "Verb (V)",
 "color": "blue",
 "text": "<strong>Predicate</strong> — action or state:",
 "example": "reads / is / have"
 },
 {
 "label": "Object (O)",
 "color": "amber",
 "text": "<strong>Object</strong> - to whom/what the action is aimed at:",
 "example": "a book / happy / two cats"
 }
 ]
}

{
 "title": "1. What is the simple sentence? predicate",
 "intro": "A simple sentence has one subject and one predicate:",
 "items": [
 {
 "label": "One subject",
 "title": "Subject",
 "subtitle": "One person or thing performs the action"
 },
 {
 "label": "One predicate",
 "title": "Verb",
 "subtitle": "One action or one state"
 },
 {
 "label": "Complete thought",
 "title": "Complete thought",
 "subtitle": "The sentence makes complete sense"
 }
 ]
}

{
 "title": "2. Subject is a word or group of words that indicates who or what is performing an action. The subject <strong>always comes first</strong> in an affirmative sentence.",
 "sections": [
 {
 "label": "What a subject is",
 "color": "emerald",
 "description": "<strong>Subject</strong> is the word or word group that shows who or what does the action. In a statement, it usually comes before the verb.",
 "examples": [
 {
 "en": "I study English.",
 "ua": "I study English."
 },
 {
 "en": "She works at a bank.",
 "ua": "She works at a bank."
 },
 {
 "en": "The children play outside.",
 "ua": "The children play outside."
 }
 ]
 },
 {
 "label": "Types of subjects",
 "color": "sky",
 "description": "The subject can be: <strong>pronoun</strong> (I, you, he, she, it, we, they), <strong>noun</strong> (Tom, dog, car), or <strong>group of words</strong> (the old man, my best friend).",
 "examples": [
 {
 "en": "He is a doctor.",
 "ua": "He is a doctor."
 },
 {
 "en": "Maria speaks Spanish.",
 "ua": "Maria speaks Spanish."
 },
 {
 "en": "My older brother lives in Kyiv.",
 "ua": "My older brother lives in Kyiv."
 }
 ]
 }
 ]
}

{
 "title": "3. Verb - Predicate (verb)",
 "sections": [
 {
 "label": "What is a predicate",
 "color": "emerald",
 "description": "<strong>Verb</strong> is a word that expresses an action or state. The predicate <strong>always comes after the subject</strong>.",
 "examples": [
 {
 "en": "She reads books.",
 "ua": "She reads books."
 },
 {
 "en": "He is happy.",
 "ua": "He is happy."
 },
 {
 "en": "They have a car.",
 "ua": "They have a car."
 }
 ]
 },
 {
 "label": "Types of verbs",
 "color": "sky",
 "description": "Main types: <strong>action verbs</strong> (actions: run, eat, write), <strong>linking verbs</strong> (connections: be, seem, become), <strong>auxiliary verbs</strong> (auxiliaries: do, have, will).",
 "examples": [
 {
 "en": "I eat breakfast at 8.",
 "ua": "I eat breakfast at 8."
 },
 {
 "en": "She is a teacher.",
 "ua": "She is a teacher."
 },
 {
 "en": "They do not like coffee.",
 "ua": "They do not like coffee."
 }
 ]
 }
 ]
}

{
 "title": "4. Object - Attachment",
 "sections": [
 {
 "label": "What is attachment",
 "color": "emerald",
 "description": "<strong>Object</strong> is a word or group of words on which an action is directed. The adjunct <strong>stands after the verb</strong>.",
 "examples": [
 {
 "en": "She reads a book.",
 "ua": "She reads a book."
 },
 {
 "en": "I love my family.",
 "ua": "I love my family."
 },
 {
 "en": "He bought a new car.",
 "ua": "He bought a new car."
 }
 ]
 },
 {
 "label": "Direct vs Indirect Object",
 "color": "sky",
 "description": "<strong>Direct object</strong> — direct object (what?), <strong>indirect object</strong> — indirect object (to whom?).",
 "examples": [
 {
 "en": "She gave me a gift.",
 "ua": "She gave me a gift."
 },
 {
 "en": "I sent him a letter.",
 "ua": "I sent him a letter."
 }
 ],
 "note": "Order: <strong>S + V + indirect object + direct object</strong> OR <strong>S + V + direct object + to/for + indirect object</strong>."
 }
 ]
}

{
 "title": "5. Complete S–V–O structure",
 "intro": "Basic scheme of a simple affirmative sentence:",
 "rows": [
 {
 "en": "Subject (S)",
 "ua": "Subject (S)",
 "note": "I, She, The dog, My friends"
 },
 {
 "en": "Verb (v) O)",
 "ua": "Verb (v) O)",
 "note": "read, is, have, like"
 },
 {
 "en": "Object (O)",
 "ua": "Object (O)",
 "note": "books, happy, a car, music"
 }
 ],
 "warning": "📌 Formula: <strong>Subject + Verb + Object</strong> (S + V + O)"
}

{
 "title": "6. Examples of sentences with the structure S–V–O",
 "sections": [
 {
 "label": "Simple examples",
 "color": "emerald",
 "description": "Basic sentences with the structure <strong>Subject + Verb + Object</strong>:",
 "examples": [
 {
 "en": "I eat breakfast.",
 "ua": "I eat breakfast."
 },
 {
 "en": "She loves music.",
 "ua": "She loves music."
 },
 {
 "en": "They play football.",
 "ua": "They play football."
 }
 ]
 },
 {
 "label": "Extended examples",
 "color": "sky",
 "description": "Sentences with word groups as subject or object:",
 "examples": [
 {
 "en": "My best friend speaks three languages.",
 "ua": "My best friend speaks three languages."
 },
 {
 "en": "The old man reads the morning newspaper.",
 "ua": "The old man reads the morning newspaper."
 },
 {
 "en": "Our teacher explains difficult grammar rules.",
 "ua": "Our teacher explains difficult grammar rules."
 }
 ]
 }
 ]
}

{
 "title": "7. Sentences without an adjunct (S–V)",
 "sections": [
 {
 "label": "Intransitive verbs",
 "color": "emerald",
 "description": "Some verbs (<strong>intransitive verbs</strong>) do not need an adjunct. Structure: <strong>S + V</strong>.",
 "examples": [
 {
 "en": "She sleeps.",
 "ua": "She sleeps."
 },
 {
 "en": "The baby cries.",
 "ua": "The baby cries."
 },
 {
 "en": "Birds fly.",
 "ua": "Birds fly."
 }
 ]
 },
 {
 "label": "The verb TO BE",
 "color": "sky",
 "description": "The verb <strong>to be</strong> is often used not as an addition, but as a <strong>complement</strong> (predicate).",
 "examples": [
 {
 "en": "She is a doctor.",
 "ua": "She is a doctor."
 },
 {
 "en": "They are happy.",
 "ua": "They are happy."
 },
 {
 "en": "I am at home.",
 "ua": "I am at home."
 }
 ]
 }
 ]
}

{
 "title": "8. Comparison: English vs Ukrainian",
 "intro": "Main difference between the languages:",
 "rows": [
 {
 "en": "English: Fixed word order",
 "ua": "English: Fixed word order",
 "note": "She reads books. ✅"
 },
 {
 "en": "Ukrainian: Flexible word order",
 "ua": "Ukrainian: Flexible word order",
 "note": "She reads books. ✅"
 },
 {
 "en": "Wrong in English",
 "ua": "Wrong in English",
 "note": "Books reads she. ❌"
 }
 ],
 "warning": "⚠️ In English, word order <strong>determines meaning</strong>. The subject and application cannot be interchanged!"
}

{
 "title": "9. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Omission of the subject by dropping the subject.",
 "wrong": "Is raining. / Am tired.",
 "right": "​​​​ <span class=\"font-mono\">It is raining. / I am tired.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Change of S–V–O order.",
 "wrong": "Books reads she every day.",
 "right": " ✅ <span class=\"font-mono\">She reads books every day.</span> Error 3. football."
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Putting the object before the verb.",
 "wrong": "I English study.",
 "right": "✅ <span class=\"font-mono\">I study English.</span>"
 },
 {
 "label": "Mistake 4",
 "color": "purple",
 "title": "Putting the subject after the verb.",
 "wrong": "Plays Tom football.",
 "right": " ✅ <span class=\"font-mono\">Tom plays football.</span>"
 }
 ]
}

{
 "title": "11. Practice",
 "select_title": "Exercise 1. Identify the elements of the sentence",
 "select_intro": "Determine which element is the highlighted word.",
 "selects": [
 {
 "label": "SHE reads books. (Subject / Verb / Object)",
 "prompt": "What element?"
 },
 {
 "label": "She READS books. (Subject / Verb / Object)",
 "prompt": "What element?"
 },
 {
 "label": "She reads BOOKS. (Subject/Verb/Object) order.",
 "prompt": "Which element?"
 }
 ],
 "options": [
 "Subject",
 "Verb",
 "Object"
 ],
 "input_title": "Exercise 2. Build S-V-O sentences",
 "input_intro": "Put the words in the correct order.",
 "inputs": [
 {
 "before": "(loves / music / Maria)",
 "after": "→"
 },
 {
 "before": "(plays / he / tennis)",
 "after": "→"
 },
 {
 "before": "(books / read / the students)",
 "after": "→"
 }
 ],
 "rephrase_title": " Exercise 3. Exercise errors",
 "rephrase_intro": "Find and correct the error in the sentence structure.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "Coffee drinks she.",
 "example_target": "She drinks coffee."
 },
 {
 "original": "1. I study English every day.",
 "placeholder": "Correct word order"
 },
 {
 "original": "2. Football play my brother.",
 "placeholder": "Fix the word order"
 }
 ]
}

